import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, Badge, icon } from 'decantr/components';

code.example:
function SessionManager({ sessions, currentSessionId, onRevoke, onRevokeAll }) {
  const { div, h3, p, span, time } = tags;

  const deviceIcon = (device) => {
    if (device.includes('iPhone') || device.includes('Android')) return 'smartphone';
    if (device.includes('iPad') || device.includes('Tablet')) return 'tablet';
    return 'monitor';
  };

  const currentSession = sessions.find(s => s.id === currentSessionId);
  const otherSessions = sessions.filter(s => s.id !== currentSessionId);

  return div({ class: css('_flex _col _gap6') },
    div({ class: css('carbon-card _p4 _r2 _borderPrimary') },
      div({ class: css('_flex _aic _gap3') },
        div({ class: css('_w10 _h10 _rfull _bgPrimary/10 _flex _center') },
          icon(deviceIcon(currentSession.device), { class: css('_fgPrimary') })
        ),
        div({ class: css('_flex1') },
          div({ class: css('_flex _aic _gap2') },
            span({ class: css('_font500') }, currentSession.device),
            Badge({ variant: 'success', size: 'xs' }, 'Current')
          ),
          p({ class: css('_textsm _fgmuted') }, `${currentSession.browser} - ${currentSession.location}`)
        )
      )
    ),
    otherSessions.length > 0 ? div({ class: css('_flex _col _gap3') },
      h3({ class: css('_heading5 _mb2') }, 'Other sessions'),
      ...otherSessions.map(session =>
        div({ class: css('carbon-card _p4 _r2 _flex _aic _gap3') },
          div({ class: css('_w10 _h10 _rfull _bgmuted/10 _flex _center') },
            icon(deviceIcon(session.device), { class: css('_fgmuted') })
          ),
          div({ class: css('_flex1') },
            span({ class: css('_font500') }, session.device),
            p({ class: css('_textsm _fgmuted') }, `${session.browser} - ${session.location}`),
            time({ class: css('_textsm _fgmuted') }, `Last active: ${session.lastActive}`)
          ),
          Button({ variant: 'ghost', size: 'sm', onclick: () => onRevoke(session.id) },
            icon('log-out', { size: '16' }), 'Revoke'
          )
        )
      )
    ) : null,
    otherSessions.length > 0 ? Button({
      variant: 'outline',
      class: css('_fgDanger _borderDanger'),
      onclick: onRevokeAll
    }, icon('log-out'), 'Sign out of all other sessions') : null
  );
}

